// ReviewsController.cs
using System;
using System.Collections.Generic;
using System.Linq;
using System.Web.Mvc;
using YourNamespace.Models; // Assuming the Review model exists in this namespace
using System.Data.Entity;  // For Include method

namespace YourNamespace.Controllers {
    public class ReviewsController : Controller {
        private ApplicationDbContext db = new ApplicationDbContext();   // Assumes you have a DbContext named ApplicationDbContext pointing to your database
    
        // GET: Reviews
        public ActionResult Index(int productId) {
            var reviews = db.Reviews.Where(r => r.ProductID == productId).Include(r => r.User);  // Assumes you have a 'Review' model and each review has an associated user (with navigation property User), and that Reviews is a DbSet of Review in your ApplicationDbContext
            return View(reviews);
        }
    }
